import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { 
  Wrench, 
  Star, 
  ArrowRight,
  Filter,
  Search,
  Clock,
  MapPin,
  Users
} from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

const ServicesPage = () => {
  const { t } = useLanguage();
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('all');

  const categories = [
    { id: 'all', name: t('allServices') },
    { id: 'plumbing', name: t('plumbing') },
    { id: 'electrical', name: t('electrical') },
    { id: 'hvac', name: t('hvac') },
    { id: 'cleaning', name: t('cleaning') },
    { id: 'renovation', name: t('renovation') },
    { id: 'maintenance', name: t('maintenance') }
  ];

  const services = [
    {
      id: 1,
      name: t('plumbing'),
      category: 'plumbing',
      description: t('plumbingDesc'),
      price: t('from') + ' SGD $50',
      duration: '1-3 ' + t('hours'),
      rating: 4.8,
      reviews: 156,
      features: [t('emergency24h'), t('proTools'), t('warranty')],
      image: '/images/plumbing.jpg'
    },
    {
      id: 2,
      name: t('electrical'),
      category: 'electrical',
      description: t('electricalDesc'),
      price: t('from') + ' SGD $80',
      duration: '2-4 ' + t('hours'),
      rating: 4.9,
      reviews: 203,
      features: [t('certifiedElectrician'), t('safetyCheck'), t('qualityAssurance')],
      image: '/images/electrical.jpg'
    },
    {
      id: 3,
      name: t('hvac'),
      category: 'hvac',
      description: t('hvacDesc'),
      price: t('from') + ' SGD $120',
      duration: '2-5 ' + t('hours'),
      rating: 4.7,
      reviews: 189,
      features: [t('deepCleaning'), t('performanceCheck'), t('regularMaintenance')],
      image: '/images/hvac.jpg'
    },
    {
      id: 4,
      name: t('cleaning'),
      category: 'cleaning',
      description: t('cleaningDesc'),
      price: t('from') + ' SGD $100',
      duration: '3-6 ' + t('hours'),
      rating: 4.6,
      reviews: 142,
      features: [t('ecoFriendly'), t('professionalEquipment'), t('satisfactionGuarantee')],
      image: '/images/cleaning.jpg'
    },
    {
      id: 5,
      name: t('renovation'),
      category: 'renovation',
      description: t('renovationDesc'),
      price: t('from') + ' SGD $500',
      duration: '1-7 ' + t('days'),
      rating: 4.5,
      reviews: 98,
      features: [t('designConsultation'), t('materialSelection'), t('constructionSupervision')],
      image: '/images/renovation.jpg'
    },
    {
      id: 6,
      name: t('maintenance'),
      category: 'maintenance',
      description: t('maintenanceDesc'),
      price: t('from') + ' SGD $200',
      duration: '2-4 ' + t('hours'),
      rating: 4.8,
      reviews: 167,
      features: [t('regularCheck'), t('preventiveMaintenance'), t('reportService')],
      image: '/images/maintenance.jpg'
    }
  ];

  const filteredServices = services.filter(service => {
    const matchesSearch = service.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         service.description.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory === 'all' || service.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <section className="bg-blue-600 text-white py-16">
        <div className="container mx-auto px-4">
          <div className="text-center">
            <h1 className="text-4xl md:text-5xl font-bold mb-4">{t('ourServices')}</h1>
            <p className="text-xl text-blue-100 max-w-2xl mx-auto">
              {t('provideFullPropertyMaintenance')}
            </p>
          </div>
        </div>
      </section>

      {/* Search and Filter */}
      <section className="py-8 bg-white border-b">
        <div className="container mx-auto px-4">
          <div className="flex flex-col md:flex-row gap-4 items-center">
            {/* Search */}
            <div className="flex-1 relative">
              <Search size={20} className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
              <input
                type="text"
                placeholder={t('searchServices')}
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:border-blue-500"
              />
            </div>

            {/* Category Filter */}
            <div className="flex items-center space-x-2">
              <Filter size={20} className="text-gray-600" />
              <select
                value={selectedCategory}
                onChange={(e) => setSelectedCategory(e.target.value)}
                className="px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:border-blue-500"
              >
                {categories.map(category => (
                  <option key={category.id} value={category.id}>
                    {category.name}
                  </option>
                ))}
              </select>
            </div>
          </div>
        </div>
      </section>

      {/* Services Grid */}
      <section className="py-16">
        <div className="container mx-auto px-4">
          {filteredServices.length === 0 ? (
            <div className="text-center py-12">
              <div className="text-gray-500 text-lg mb-4">{t('noMatchingServices')}</div>
              <button
                onClick={() => {
                  setSearchTerm('');
                  setSelectedCategory('all');
                }}
                className="text-blue-600 hover:text-blue-700 font-medium"
              >
                {t('clearFilters')}
              </button>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {filteredServices.map((service, index) => (
                <motion.div
                  key={service.id}
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.5, delay: index * 0.1 }}
                  className="bg-white rounded-xl shadow-lg overflow-hidden hover:shadow-xl transition-shadow"
                >
                  {/* Service Image */}
                  <div className="h-48 bg-gray-200 flex items-center justify-center">
                    <Wrench size={48} className="text-gray-400" />
                  </div>

                  {/* Service Content */}
                  <div className="p-6">
                    <div className="flex items-center justify-between mb-2">
                      <h3 className="text-xl font-semibold">{service.name}</h3>
                      <div className="flex items-center">
                        <Star size={16} className="text-yellow-400 fill-current" />
                        <span className="text-sm text-gray-600 ml-1">
                          {service.rating} ({service.reviews})
                        </span>
                      </div>
                    </div>

                    <p className="text-gray-600 mb-4">{service.description}</p>

                    {/* Service Details */}
                    <div className="space-y-2 mb-4">
                      <div className="flex items-center text-sm text-gray-600">
                        <Clock size={16} className="mr-2" />
                        <span>{t('serviceDuration')}: {service.duration}</span>
                      </div>
                      <div className="flex items-center text-sm text-gray-600">
                        <Users size={16} className="mr-2" />
                        <span>{t('professionalTechnicians')}</span>
                      </div>
                    </div>

                    {/* Features */}
                    <div className="mb-4">
                      <div className="flex flex-wrap gap-2">
                        {service.features.map((feature, idx) => (
                          <span
                            key={idx}
                            className="px-2 py-1 bg-blue-100 text-blue-600 text-xs rounded-full"
                          >
                            {feature}
                          </span>
                        ))}
                      </div>
                    </div>

                    {/* Price and Action */}
                    <div className="flex items-center justify-between">
                      <div>
                        <span className="text-2xl font-bold text-blue-600">{service.price}</span>
                      </div>
                      <Link
                        to={`/services/${service.id}`}
                        className="bg-blue-600 text-white px-6 py-2 rounded-lg hover:bg-blue-700 transition-colors inline-flex items-center"
                      >
                        {t('viewDetails')}
                        <ArrowRight size={16} className="ml-1" />
                      </Link>
                    </div>
                  </div>
                </motion.div>
              ))}
            </div>
          )}
        </div>
      </section>

      {/* CTA Section */}
      <section className="py-16 bg-blue-600 text-white">
        <div className="container mx-auto px-4 text-center">
          <h2 className="text-3xl font-bold mb-4">{t('needCustomService')}</h2>
          <p className="text-xl mb-8 text-blue-100 max-w-2xl mx-auto">
            {t('contactUsForCustomQuotes')}
          </p>
          <div className="flex flex-col sm:flex-row gap-4 justify-center">
            <Link
              to="/contact"
              className="bg-white text-blue-600 px-8 py-3 rounded-lg font-semibold hover:bg-gray-100 transition-colors inline-flex items-center"
            >
              {t('contactUs')}
              <ArrowRight size={20} className="ml-2" />
            </Link>
            <Link
              to="/booking"
              className="border border-white text-white px-8 py-3 rounded-lg font-semibold hover:bg-white hover:text-blue-600 transition-colors"
            >
              {t('bookNow')}
            </Link>
          </div>
        </div>
      </section>
    </div>
  );
};

export default ServicesPage;
